     1→import { useQuery } from "@tanstack/react-query";
     2→import { useEffect, useState } from "react";
     3→import { LoginForm } from "./components/auth/login-form";
     4→import { SignupForm } from "./components/auth/signup-form";
     5→import { Button } from "./components/ui/button";
     6→import { authClient } from "./lib/auth-client";
     7→import { orpc } from "./lib/orpc";
     8→
     9→type Page = "login" | "signup";
    10→
    11→function getCliParams(): { cliCallback: string; state: string } | null {
    12→	const params = new URLSearchParams(window.location.search);
    13→	const cliCallback = params.get("cli_callback");
    14→	const state = params.get("state");
    15→	if (!cliCallback || !state) return null;
    16→	try {
    17→		const url = new URL(cliCallback);
    18→		if (url.hostname !== "127.0.0.1") return null;
    19→	} catch {
    20→		return null;
    21→	}
    22→	return { cliCallback, state };
    23→}
    24→
    25→function App() {
    26→	const { data: session, isPending } = authClient.useSession();
    27→	const [page, setPage] = useState<Page>("login");
    28→	const [cliRedirecting, setCliRedirecting] = useState(false);
    29→	const health = useQuery(orpc.health.queryOptions({}));
    30→	const cliParams = getCliParams();
    31→
    32→	useEffect(() => {
    33→		if (!session || !cliParams || cliRedirecting) return;
    34→		setCliRedirecting(true);
    35→
    36→		fetch("/api/cli-token", { credentials: "include" })
    37→			.then((res) => res.json())
    38→			.then((data: { token: string }) => {
    39→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
    40→				window.location.href = redirectUrl;
    41→			});
    42→	}, [session, cliParams, cliRedirecting]);
    43→
    44→	if (isPending) {
    45→		return (
    46→			<div className="flex min-h-screen items-center justify-center">
    47→				<p className="text-muted-foreground">Loading...</p>
    48→			</div>
    49→		);
    50→	}
    51→
    52→	if (cliRedirecting) {
    53→		return (
    54→			<div className="flex min-h-screen items-center justify-center">
    55→				<p className="text-muted-foreground">Completing CLI login...</p>
    56→			</div>
    57→		);
    58→	}
    59→
    60→	if (!session) {
    61→		return (
    62→			<div className="flex min-h-screen items-center justify-center">
    63→				{page === "login" ? (
    64→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
    65→				) : (
    66→					<SignupForm onSwitchToLogin={() => setPage("login")} />
    67→				)}
    68→			</div>
    69→		);
    70→	}
    71→
    72→	return (
    73→		<div className="flex min-h-screen flex-col items-center justify-center gap-4">
    74→			<h1 className="text-4xl font-bold">Melbourne</h1>
    75→			<p className="text-muted-foreground">
    76→				Signed in as {session.user.name} ({session.user.email})
    77→			</p>
    78→			<p className="text-muted-foreground">
    79→				API status:{" "}
    80→				{health.isLoading
    81→					? "checking..."
    82→					: health.data
    83→						? health.data.status
    84→						: "offline"}
    85→			</p>
    86→			<div className="flex gap-2">
    87→				<Button type="button" onClick={() => health.refetch()}>Check Health</Button>
    88→				<Button type="button" variant="outline" onClick={() => authClient.signOut()}>
    89→					Sign out
    90→				</Button>
    91→			</div>
    92→		</div>
    93→	);
    94→}
    95→
    96→export default App;
    97→

