     1→import { buildCommand } from "@stricli/core";
     2→import { classifySession } from "../lib/classifier.js";
     3→import { loadCredentials } from "../lib/credentials.js";
     4→import { getGitInfo } from "../lib/git-info.js";
     5→import { resolveSession } from "../lib/session-resolver.js";
     6→import { readSubagentFiles } from "../lib/subagent-reader.js";
     7→import { extractAgentIds, readTranscript } from "../lib/transcript-reader.js";
     8→import {
     9→	DEFAULT_ENDPOINT,
    10→	type IngestRequest,
    11→	SESSION_TAGS,
    12→	type SessionTag,
    13→	type SubagentFile,
    14→} from "../lib/types.js";
    15→import { uploadSession } from "../lib/uploader.js";
    16→
    17→async function runUpload(
    18→	flags: {
    19→		tag?: SessionTag;
    20→		endpoint: string;
    21→		classify: boolean;
    22→		dryRun: boolean;
    23→	},
    24→	session: string,
    25→): Promise<void> {
    26→	const write = (msg: string) => {
    27→		process.stdout.write(`${msg}\n`);
    28→	};
    29→	const writeError = (msg: string) => {
    30→		process.stderr.write(`${msg}\n`);
    31→	};
    32→
    33→	// Load credentials
    34→	const credentials = loadCredentials();
    35→	if (!credentials && !flags.dryRun) {
    36→		writeError("Error: Not authenticated. Run `rudel login` first.");
    37→		process.exitCode = 1;
    38→		return;
    39→	}
    40→
    41→	// Resolve session (by ID or path)
    42→	write(`Resolving session: ${session}`);
    43→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
    44→	try {
    45→		sessionInfo = await resolveSession(session);
    46→	} catch (error) {
    47→		writeError(
    48→			`Error: ${error instanceof Error ? error.message : String(error)}`,
    49→		);
    50→		process.exitCode = 1;
    51→		return;
    52→	}
    53→	write(`Found session at: ${sessionInfo.transcriptPath}`);
    54→
    55→	// Read transcript
    56→	write("Reading transcript...");
    57→	let content: string;
    58→	try {
    59→		content = await readTranscript(sessionInfo.transcriptPath);
    60→	} catch (error) {
    61→		writeError(
    62→			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
    63→		);
    64→		process.exitCode = 1;
    65→		return;
    66→	}
    67→	write(`Transcript: ${content.length} bytes`);
    68→
    69→	// Extract and read subagents
    70→	const agentIds = extractAgentIds(content);
    71→	let subagents: SubagentFile[] = [];
    72→	if (agentIds.length > 0) {
    73→		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
    74→		subagents = await readSubagentFiles(
    75→			sessionInfo.sessionDir,
    76→			agentIds,
    77→			sessionInfo.sessionId,
    78→		);
    79→		write(
    80→			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
    81→		);
    82→	}
    83→
    84→	// Get git info
    85→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
    86→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
    87→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
    88→
    89→	// Classify if requested
    90→	let tag = flags.tag;
    91→	if (!tag && flags.classify) {
    92→		write("Classifying session...");
    93→		tag = (await classifySession(content)) ?? undefined;
    94→		if (tag) write(`Classified as: ${tag}`);
    95→	}
    96→
    97→	// Build request
    98→	const request: IngestRequest = {
    99→		sessionId: sessionInfo.sessionId,
   100→		projectPath: sessionInfo.projectPath,
   101→		repository: gitInfo.repository,
   102→		gitBranch: gitInfo.branch,
   103→		gitSha: gitInfo.sha,
   104→		tag,
   105→		content,
   106→		subagents: subagents.length > 0 ? subagents : undefined,
   107→	};
   108→
   109→	// Upload or dry-run
   110→	if (flags.dryRun) {
   111→		const preview = {
   112→			...request,
   113→			content: `[${request.content.length} bytes]`,
   114→			subagents: request.subagents?.map((s) => ({
   115→				...s,
   116→				content: `[${s.content.length} bytes]`,
   117→			})),
   118→		};
   119→		write("Dry run - would upload:");
   120→		write(JSON.stringify(preview, null, 2));
   121→		return;
   122→	}
   123→
   124→	write("Uploading...");
   125→	const result = await uploadSession(request, {
   126→		endpoint: flags.endpoint,
   127→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
   128→		token: credentials!.token,
   129→	});
   130→
   131→	if (result.success) {
   132→		write("Upload successful!");
   133→	} else {
   134→		writeError(`Upload failed: ${result.error}`);
   135→		process.exitCode = 1;
   136→	}
   137→}
   138→
   139→export const uploadCommand = buildCommand({
   140→	loader: async () => ({ default: runUpload }),
   141→	parameters: {
   142→		positional: {
   143→			kind: "tuple",
   144→			parameters: [
   145→				{
   146→					brief: "Session ID or path to a session .jsonl file",
   147→					parse: String,
   148→					placeholder: "session",
   149→				},
   150→			],
   151→		},
   152→		flags: {
   153→			tag: {
   154→				kind: "enum",
   155→				values: [...SESSION_TAGS],
   156→				brief: "Session tag/category",
   157→				optional: true,
   158→			},
   159→			endpoint: {
   160→				kind: "parsed",
   161→				parse: String,
   162→				brief: "Override the upload endpoint URL",
   163→				default: DEFAULT_ENDPOINT,
   164→			},
   165→			classify: {
   166→				kind: "boolean",
   167→				brief: "Auto-classify session tag using Claude CLI",
   168→				default: false,
   169→			},
   170→			dryRun: {
   171→				kind: "boolean",
   172→				brief: "Preview what would be uploaded without sending",
   173→				default: false,
   174→			},
   175→		},
   176→		aliases: {
   177→			t: "tag",
   178→			c: "classify",
   179→			n: "dryRun",
   180→		},
   181→	},
   182→	docs: {
   183→		brief: "Upload a Claude Code session transcript to the backend",
   184→	},
   185→});
